-- Verificar se já enviamos este nível de alerta para esta interação
SELECT interacao_id, alerta_nivel
FROM god_mention_alerts
WHERE interacao_id = {{ $json.interacao_id }}
  AND alerta_nivel = {{ $json.alerta_nivel }}

