// Montar mensagem de alerta escalonada
const data = $input.first().json;
const nivel = data.alerta_nivel;
const horas = Math.round(data.horas_pendente);
const mentorado = data.mentorado_nome;
const conteudo = (data.conteudo || '').substring(0, 150);
const membro = data.membro_mencionado;

const emojis = ['', '⏰', '⚠️', '🔴', '🚨'];
const urgencias = ['', 'Lembrete', 'Atenção', 'Urgente', 'CRÍTICO'];

const msg = `${emojis[nivel]} *${urgencias[nivel]}* — Menção sem resposta há ${horas}h

👤 *${mentorado}* te mencionou no grupo:

_"${conteudo}${conteudo.length >= 150 ? '...' : ''}"_

⏳ Pendente há *${horas} horas*
${nivel >= 3 ? '\n❗ Essa é a ' + nivel + 'ª notificação. Por favor responda o mais rápido possível.' : ''}

— Spalla Bot 🤖`;

return [{
  json: {
    ...data,
    alert_message: msg,
    whatsapp_to: data.membro_whatsapp + '@s.whatsapp.net'
  }
}];
